import scala.collection.mutable.ArrayBuffer

def gcd(a: Long, b: Long): Long = {
    if (b == 0) Math.abs(a) else gcd(b, a % b)
}

def solve(nums: Array[Long], maxC: Long): Long = {
    val n = nums.length

    def feasible(L: Long): Boolean = {
        if (L == 0) {
            var countNonOne = 0L
            for (x <- nums) {
                if (x != 1) countNonOne += 1
            }
            countNonOne <= maxC
        } else {
            var totalBreaks = 0L
            var i = 0
            while (i < n) {
                if (nums(i) == 1) {
                    i += 1
                } else {
                    var j = i
                    while (j < n && nums(j) != 1) {
                        j += 1
                    }
                    val k = j - i
                    if (k <= L) {
                    } else {
                        val seg = nums.slice(i, j)
                        val segLen = k
                        val LOG = 20
                        val st = Array.ofDim[Long](segLen, LOG)

                        for (idx <- 0 until segLen) {
                            st(idx)(0) = seg(idx)
                        }

                        for (lj <- 1 until LOG) {
                            for (idx <- 0 until segLen) {
                                val nextIdx = idx + (1 << (lj-1))
                                if (nextIdx < segLen) {
                                    st(idx)(lj) = gcd(st(idx)(lj-1), st(nextIdx)(lj-1))
                                } else {
                                    st(idx)(lj) = st(idx)(lj-1)
                                }
                            }
                        }

                        def query(l: Int, r: Int): Long = {
                            val len = r - l + 1
                            if (len <= 0) return 0
                            var bit = 0
                            var temp = len
                            while (temp > 1) {
                                bit += 1
                                temp >>= 1
                            }
                            val power = 1 << bit
                            val a = st(l)(bit)
                            val b = if (r - power + 1 >= l) st(r - power + 1)(bit) else 0
                            gcd(a, b)
                        }

                        val windowSize = (L+1).toInt
                        val intervalsEnd = ArrayBuffer[Int]()
                        for (start <- 0 to segLen - windowSize) {
                            val g = query(start, start + windowSize - 1)
                            if (g > 1) {
                                intervalsEnd += start + windowSize - 1
                            }
                        }

                        val sortedEnds = intervalsEnd.sorted
                        var breaksInSegment = 0
                        var lastBreakIndex = -1
                        for (endPos <- sortedEnds) {
                            if (lastBreakIndex < 0 || lastBreakIndex < endPos - windowSize + 1) {
                                breaksInSegment += 1
                                lastBreakIndex = endPos
                            }
                        }

                        totalBreaks += breaksInSegment
                    }
                    i = j
                }
                if (totalBreaks > maxC) return false
            }
            totalBreaks <= maxC
        }
    }

    var low: Long = 0
    var high: Long = n
    var ans: Long = high
    while (low <= high) {
        val mid = (low + high) / 2
        if (feasible(mid)) {
            ans = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    ans
}
```

