def solve(nums: Array[Long], maxC: Long): Long = {
    @scala.annotation.tailrec
    def gcd(a: Long, b: Long): Long = {
        if (b == 0) a else gcd(b, a % b)
    }

    val n = nums.length
    if (n == 0) return 0L

    val maxJ = 32 - Integer.numberOfLeadingZeros(n - 1)
    val st = Array.ofDim[Long](n, maxJ + 1)

    for (i <- 0 until n) {
        st(i)(0) = nums(i)
    }

    for (j <- 1 to maxJ) {
        val lenBlock = 1 << (j - 1)
        val totalBlock = 1 << j
        val maxI = n - totalBlock
        if (maxI >= 0) {
            for (i <- 0 to maxI) {
                st(i)(j) = gcd(st(i)(j - 1), st(i + lenBlock)(j - 1))
            }
        }
    }

    def query(l: Int, r: Int): Long = {
        val len = r - l + 1
        if (len == 1) {
            nums(l)
        } else {
            val k = 31 - Integer.numberOfLeadingZeros(len)
            val blockSize = 1 << k
            val res = gcd(st(l)(k), st(r - blockSize + 1)(k))
            res
