    def check(X: Int): Boolean = {
        val L = X + 1
        if (L > n) {
            true
        } else {
            var stableSegments = List.empty[(Int, Int)]
            for (i <- 0 to (n - L)) {
                val g = query(i, i + L - 1)
                if (g >= 2) {
                    stableSegments = (i, i + L - 1) :: stableSegments
                }
