            val sortedSegments = stableSegments.sortBy(_._2)
            var lastBreak = -1
            var count = 0
            for ((s, e) <- sortedSegments) {
                if (lastBreak < s) {
                    count += 1
                    lastBreak = e
                }
            }
            count <= maxC
        }
    }

    var low = 0
    var high = n
    var ans = n
    while (low <= high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            ans = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    ans
}
