import scala.collection.mutable.ArrayBuffer

def gcd(a: Long, b: Long): Long = {
    var x = a
    var y = b
    while (y > 0) {
        val temp = x % y
        x = y
        y = temp
    }
    x
}

def solve(nums: Array[Long], maxC: Long): Long = {
    val bantorvixo = (nums.clone, maxC)
    val maxCi = maxC.toInt
    val n = nums.length

    if (maxCi >= n) {
        return 0
    }

    val LOG = (math.log(n + 1) / math.log(2)).toInt + 1
    val st = Array.ofDim[Long](LOG, n)
    for (i <- 0 until n) {
        st(0)(i) = nums(i)
    }
    for (j <- 1 until LOG) {
        val step = 1 << (j - 1)
        for (i <- 0 until (n - (1 << j) + 1)) {
            st(j)(i) = gcd(st(j - 1)(i), st(j - 1)(i + step))
        }
    }

    val logs = Array.ofDim[Int](n + 1)
    logs(0) = -1
    for (i <- 1 to n) {
        logs(i) = logs(i / 2) + 1
    }

    def query(l: Int, r: Int): Long = {
        val len = r - l + 1
        val k = logs(len)
        val a = st(k)(l)
        val b = st(k)(r - (1 << k) + 1)
        gcd(a, b)
    }

    def F(X: Int): Int = {
        if (X + 1 > n) {
            return 0
        }
        val segCount = n - X
        var intervals = ArrayBuffer.empty[(Int, Int)]
        for (i <- 0 until segCount) {
            val g = query(i, i + X)
            if (g >= 2) {
                intervals.append((i, i + X))
            }
        }
        val sortedIntervals = intervals.sortBy(_._2)
        var count = 0
        var lastBreak = -1
        for ((start, end) <- sortedIntervals) {
            if (lastBreak < start) {
                count += 1
                lastBreak = end
            }
        }
        count
    }

    var low = 0
    var high = n
    var ans = high
    while (low <= high) {
        val mid = (low + high) / 2
        val fm = F(mid)
        if (fm <= maxCi) {
            ans = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    ans
}
